{
  "$schema": "https://opencode.ai/config.json",
  "permission": {
    "websearch": "allow"
  },
  "provider": {
    "nvidia": {
      "npm": "@ai-sdk/openai-compatible",
      "name": "NVIDIA NIM",
      "options": {
        "baseURL": "https://integrate.api.nvidia.com/v1",
        "apiKey": "{env:NVIDIA_API_KEY}"
      },
      "models": {
        "deepseek-ai/deepseek-v4-pro": {
          "name": "DeepSeek V4 Pro",
          "limit": {
            "context": 1000000,
            "output": 32768
          }
        }
      }
    }
  }
}

{
  "lastChangelogVersion": "0.75.5",
  "defaultProvider": "kimi-coder",
  "defaultModel": "kimi-k2.6",
  "defaultThinkingLevel": "high",
  "hideThinkingBlock": false,
  "thinkingBudgets": {
    "minimal": 1024,
    "low": 4096,
    "medium": 10240,
    "high": 32768
  },
  "packages": [
    "npm:pi-subagents",
    "npm:pi-agent-flow",
    "npm:pi-kimi-coder",
    "npm:pi-lsp-extension",
    "npm:@juicesharp/rpiv-web-tools",
    "npm:pi-mcp-adapter"
  ],
  "modelCycles": [
    "kimi-coder/kimi-for-coding",
    "deepseek/deepseek-v4-pro",
    "deepseek/deepseek-v4-flash"
  ],
  "subagents": {
    "agentOverrides": {
      "scout": {
        "model": "deepseek/deepseek-v4-flash",
        "thinking": "off",
        "fallbackModels": ["deepseek/deepseek-v4-pro"]
      },
      "researcher": {
        "model": "deepseek/deepseek-v4-pro",
        "thinking": "max",
        "fallbackModels": ["kimi-coder/kimi-k2.6"]
      },
      "planner": {
        "model": "kimi-coder/kimi-k2.6",
        "thinking": "max",
        "fallbackModels": ["deepseek/deepseek-v4-pro"]
      },
      "worker": {
        "model": "kimi-coder/kimi-for-coding",
        "thinking": "max",
        "fallbackModels": ["deepseek/deepseek-v4-pro"]
      },
      "reviewer": {
        "model": "deepseek/deepseek-v4-pro",
        "thinking": "max",
        "fallbackModels": ["kimi-coder/kimi-for-coding"]
      },
      "context-builder": {
        "model": "deepseek/deepseek-v4-flash",
        "thinking": "low",
        "fallbackModels": ["deepseek/deepseek-v4-pro"]
      },
      "oracle": {
        "model": "deepseek/deepseek-v4-pro",
        "thinking": "max",
        "fallbackModels": ["kimi-coder/kimi-k2.6"]
      },
      "delegate": {
        "model": "deepseek/deepseek-v4-flash",
        "thinking": "low",
        "fallbackModels": ["deepseek/deepseek-v4-pro"]
      }
    }
  }
}

{
  "mcpServers": {
    "chrome-devtools": {
      "command": "npx",
      "args": ["-y", "chrome-devtools-mcp@latest"]
    },
    "playwright": {
      "command": "npx",
      "args": ["-y", "@playwright/mcp@latest"]
    }
  }
}
